#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        vector<long long> A(N + 1);
        for (int i = 1; i <= N; ++i) cin >> A[i];

        vector<vector<int>> adj(N + 1);
        for (int i = 0; i < N - 1; ++i) {
            int u, v;
            cin >> u >> v;
            adj[u].push_back(v);
            adj[v].push_back(u);
        }

        vector<int> parent(N + 1, 0), order;
        order.reserve(N);
        vector<int> st;
        st.push_back(1);
        parent[1] = 0;

        while (!st.empty()) {
            int u = st.back();
            st.pop_back();
            order.push_back(u);
            for (int v : adj[u]) {
                if (v == parent[u]) continue;
                parent[v] = u;
                st.push_back(v);
            }
        }

        vector<long long> subG(N + 1, 0);
        vector<long long> S(N + 1, 0);
        for (int i = N - 1; i >= 0; --i) {
            int u = order[i];
            long long g = A[u];
            long long s = 0;
            for (int v : adj[u]) {
                if (v == parent[u]) continue;
                g = std::gcd(g, subG[v]);
                s += subG[v];
            }
            subG[u] = g;
            S[u] = s;
        }

        vector<long long> prefS(N + 1, 0);
        vector<long long> prefSub(N + 1, 0);

        prefS[1] = S[1];
        prefSub[1] = 0;

        for (int u : order) {
            if (u == 1) continue;
            int p = parent[u];
            prefS[u] = prefS[p] + S[u];
            prefSub[u] = prefSub[p] + subG[u];
        }

        long long ans = 0;
        for (int v = 1; v <= N; ++v) {
            long long cur = prefS[v] - prefSub[v];
            if (cur > ans) ans = cur;
        }

        cout << ans << '\n';
    }

    return 0;
}

